import { Sudoku } from './sudoku';

export class Game {
  constructor() {
    this.sudoku = new Sudoku(); 
    this.history = [];
    this.redoStack = [];
    this.isPaused = false;
  }

  getSudoku() {
    return this.sudoku;
  }

  // 同样兼容两种传参方式
  guess(rowOrObject, col, value) {
    if (this.isPaused) return;
    this.makeMove(rowOrObject, col, value);
  }

  makeMove(rowOrObject, col, value) {
    // 每次移动前，保存当前状态的深拷贝
    this.history.push(this.sudoku.clone());
    this.redoStack = []; 
    // 调用底层 sudoku 的兼容性 guess
    this.sudoku.guess(rowOrObject, col, value);
  }

  undo() {
    if (this.canUndo()) {
      this.redoStack.push(this.sudoku.clone());
      this.sudoku = this.history.pop();
    }
  }

  redo() {
    if (this.canRedo()) {
      this.history.push(this.sudoku.clone());
      this.sudoku = this.redoStack.pop();
    }
  }

  canUndo() { return this.history.length > 0; }
  canRedo() { return this.redoStack.length > 0; }

  toJSON() {
    return {
      sudoku: this.sudoku.toJSON(),
      history: this.history.map(s => s.toJSON()),
      redoStack: this.redoStack.map(s => s.toJSON())
    };
  }

  startNew(diff) {
    this.sudoku = Sudoku.generate(diff);
    this.history = [];
    this.redoStack = [];
    this.isPaused = false;
  }

  pause() { this.isPaused = true; }
  resume() { this.isPaused = false; }
}
